     1→package cmd
     2→
     3→import (
     4→	"fmt"
     5→	"net"
     6→	"os"
     7→	"os/exec"
     8→	"strconv"
     9→	"strings"
    10→	"time"
    11→
    12→	"github.com/sandcastle/cli/api"
    13→	"github.com/spf13/cobra"
    14→)
    15→
    16→func init() {
    17→	rootCmd.AddCommand(connectCmd)
    18→	rootCmd.AddCommand(sshCmd)
    19→}
    20→
    21→var connectCmd = &cobra.Command{
    22→	Use:   "connect [name]",
    23→	Short: "SSH into sandbox and attach tmux (auto-starts if stopped)",
    24→	Args:  cobra.MaximumNArgs(1),
    25→	RunE: func(cmd *cobra.Command, args []string) error {
    26→		name := resolveSandboxName(args)
    27→		if name == "" {
    28→			return fmt.Errorf("specify a sandbox name or set one with: sandcastle use <name>")
    29→		}
    30→
    31→		client, err := api.NewClient()
    32→		if err != nil {
    33→			return err
    34→		}
    35→		printServer(client)
    36→
    37→		sandbox, err := findSandboxByName(client, name)
    38→		if err != nil {
    39→			return err
    40→		}
    41→
    42→		// Auto-start if stopped
    43→		if sandbox.Status == "stopped" {
    44→			fmt.Printf("Starting sandbox %q...\n", name)
    45→			sandbox, err = client.StartSandbox(sandbox.ID)
    46→			if err != nil {
    47→				return fmt.Errorf("failed to start sandbox: %w", err)
    48→			}
    49→		}
    50→
    51→		info, err := client.ConnectInfo(sandbox.ID)
    52→		if err != nil {
    53→			return err
    54→		}
    55→
    56→		if err := waitForSSH(info.Host, info.Port); err != nil {
    57→			return err
    58→		}
    59→
    60→		// SSH with tmux attach-or-create
    61→		return sshExec(info.Host, info.Port, info.User, "tmux new-session -A -s main")
    62→	},
    63→}
    64→
    65→var sshCmd = &cobra.Command{
    66→	Use:   "ssh [name]",
    67→	Short: "SSH into sandbox shell (without tmux)",
    68→	Args:  cobra.MaximumNArgs(1),
    69→	RunE: func(cmd *cobra.Command, args []string) error {
    70→		name := resolveSandboxName(args)
    71→		if name == "" {
    72→			return fmt.Errorf("specify a sandbox name or set one with: sandcastle use <name>")
    73→		}
    74→
    75→		client, err := api.NewClient()
    76→		if err != nil {
    77→			return err
    78→		}
    79→		printServer(client)
    80→
    81→		sandbox, err := findSandboxByName(client, name)
    82→		if err != nil {
    83→			return err
    84→		}
    85→
    86→		info, err := client.ConnectInfo(sandbox.ID)
    87→		if err != nil {
    88→			return err
    89→		}
    90→
    91→		if err := waitForSSH(info.Host, info.Port); err != nil {
    92→			return err
    93→		}
    94→
    95→		return sshExec(info.Host, info.Port, info.User, "")
    96→	},
    97→}
    98→
    99→func resolveSandboxName(args []string) string {
   100→	if len(args) > 0 {
   101→		return args[0]
   102→	}
   103→	return ""
   104→}
   105→
   106→func waitForSSH(host string, port int) error {
   107→	addr := net.JoinHostPort(host, strconv.Itoa(port))
   108→	deadline := time.Now().Add(30 * time.Second)
   109→	printed := false
   110→
   111→	if os.Getenv("VERBOSE") == "1" {
   112→		fmt.Fprintf(os.Stderr, "\033[2m[verbose] Waiting for SSH at %s (timeout: 30s)\033[0m\n", addr)
   113→	}
   114→
   115→	for time.Now().Before(deadline) {
   116→		conn, err := net.DialTimeout("tcp", addr, time.Second)
   117→		if err == nil {
   118→			conn.Close()
   119→			if printed {
   120→				fmt.Println()
   121→			}
   122→			if os.Getenv("VERBOSE") == "1" {
   123→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] SSH connection successful!\033[0m\n")
   124→			}
   125→			return nil
   126→		}
   127→		if !printed {
   128→			fmt.Printf("Waiting for SSH to be ready...")
   129→			printed = true
   130→		}
   131→		fmt.Print(".")
   132→		time.Sleep(500 * time.Millisecond)
   133→	}
   134→
   135→	fmt.Println()
   136→	return fmt.Errorf("timeout waiting for SSH at %s", addr)
   137→}
   138→
   139→func sshExec(host string, port int, user string, remoteCmd string) error {
   140→	sshArgs := []string{
   141→		"-p", strconv.Itoa(port),
   142→		"-o", "StrictHostKeyChecking=no",
   143→		"-o", "UserKnownHostsFile=/dev/null",
   144→		"-o", "LogLevel=ERROR",
   145→		fmt.Sprintf("%s@%s", user, host),
   146→	}
   147→	if remoteCmd != "" {
   148→		sshArgs = append(sshArgs, "-t", remoteCmd)
   149→	}
   150→
   151→	sshPath, err := exec.LookPath("ssh")
   152→	if err != nil {
   153→		return fmt.Errorf("ssh not found: %w", err)
   154→	}
   155→
   156→	if os.Getenv("VERBOSE") == "1" {
   157→		fmt.Fprintf(os.Stderr, "→ ssh %s\n", shellJoin(sshArgs))
   158→	}
   159→
   160→	proc := &os.ProcAttr{
   161→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
   162→	}
   163→	process, err := os.StartProcess(sshPath, append([]string{"ssh"}, sshArgs...), proc)
   164→	if err != nil {
   165→		return fmt.Errorf("starting ssh: %w", err)
   166→	}
   167→
   168→	state, err := process.Wait()
   169→	if err != nil {
   170→		return err
   171→	}
   172→	if !state.Success() {
   173→		os.Exit(state.ExitCode())
   174→	}
   175→	return nil
   176→}
   177→
   178→func shellJoin(args []string) string {
   179→	quoted := make([]string, len(args))
   180→	for i, a := range args {
   181→		if strings.ContainsAny(a, " \t\n\"'\\") {
   182→			quoted[i] = fmt.Sprintf("%q", a)
   183→		} else {
   184→			quoted[i] = a
   185→		}
   186→	}
   187→	return strings.Join(quoted, " ")
   188→}
