    31→type Client struct {
    32→	BaseURL     string
    33→	Token       string
    34→	ServerAlias string
    35→	HTTPClient  *http.Client
    36→}
    37→
    38→func newHTTPClient(insecure bool) *http.Client {
    39→	if insecure {
    40→		return &http.Client{
    41→			Transport: &http.Transport{
    42→				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
    43→			},
    44→		}
    45→	}
    46→	return &http.Client{}
    47→}
    48→
    49→func NewClient() (*Client, error) {
    50→	cfg, err := config.Load()
    51→	if err != nil {
    52→		return nil, err
    53→	}
    54→	srv, err := cfg.CurrentServerConfig()
    55→	if err != nil {
    56→		return nil, err
    57→	}
    58→	logVerbose("server: %s (%s)", cfg.CurrentServer, srv.URL)
    59→	return &Client{
    60→		BaseURL:     srv.URL,
    61→		Token:       srv.Token,
    62→		ServerAlias: cfg.CurrentServer,
    63→		HTTPClient:  newHTTPClient(srv.Insecure),
    64→	}, nil
    65→}
    66→
    67→func NewClientWithToken(baseURL, token string, insecure bool) *Client {
    68→	return &Client{
    69→		BaseURL:    baseURL,
    70→		Token:      token,
    71→		HTTPClient: newHTTPClient(insecure),
    72→	}
    73→}
    74→
    75→func (c *Client) do(method, path string, body any, result any) error {
    76→	var bodyReader io.Reader
    77→	var reqData []byte
    78→	if body != nil {
    79→		var err error
    80→		reqData, err = json.Marshal(body)
    81→		if err != nil {
    82→			return fmt.Errorf("marshaling request: %w", err)
    83→		}
    84→		bodyReader = bytes.NewReader(reqData)
    85→	}
    86→
    87→	logVerbose("→ %s %s%s", method, c.BaseURL, path)
    88→	if len(reqData) > 0 {
    89→		logVerbose("  request: %s", string(reqData))
    90→	}
    91→
    92→	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
    93→	if err != nil {
    94→		return fmt.Errorf("creating request: %w", err)
    95→	}
    96→
    97→	req.Header.Set("Content-Type", "application/json")
    98→	if c.Token != "" {
    99→		req.Header.Set("Authorization", "Bearer "+c.Token)
   100→	}
   101→
   102→	resp, err := c.HTTPClient.Do(req)
   103→	if err != nil {
   104→		return fmt.Errorf("request failed: %w", err)
   105→	}
   106→	defer resp.Body.Close()
   107→
   108→	respBody, err := io.ReadAll(resp.Body)
   109→	if err != nil {
   110→		return fmt.Errorf("reading response: %w", err)
   111→	}
   112→
   113→	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
   114→	if len(respBody) > 0 {
   115→		logVerbose("  response: %s", string(respBody))
   116→	}
   117→
   118→	if resp.StatusCode >= 400 {
   119→		var apiErr APIError
   120→		if json.Unmarshal(respBody, &apiErr) == nil && apiErr.Error != "" {
   121→			return fmt.Errorf("API error (%d): %s", resp.StatusCode, apiErr.Error)
   122→		}
   123→		return fmt.Errorf("API error (%d): %s", resp.StatusCode, string(respBody))
   124→	}
   125→
   126→	if result != nil {
   127→		if err := json.Unmarshal(respBody, result); err != nil {
   128→			return fmt.Errorf("parsing response: %w", err)
   129→		}
   130→	}
   131→	return nil
   132→}
