   276→					route = strings.Join(parts, ", ")
   277→				}
   278→				fmt.Fprintf(w, "%s\t%s\t%d\t%s\t%s\t%s\n", name, s.Status, s.SSHPort, route, tsIP, s.Image)
   279→			} else {
   280→				fmt.Fprintf(w, "%s\t%s\t%d\t%s\t%s\n", name, s.Status, s.SSHPort, tsIP, s.Image)
   281→			}
   282→		}
   283→		w.Flush()
   284→		return nil
   285→	},
   286→}
