   385→				fmt.Println("No servers configured — run: sandcastle login <url>")
   386→				return nil
   387→			}
   388→
   389→			aliases := make([]string, 0, len(cfg.Servers))
   390→			for alias := range cfg.Servers {
   391→				aliases = append(aliases, alias)
   392→			}
   393→			sort.Strings(aliases)
   394→
   395→			for _, alias := range aliases {
   396→				srv := cfg.Servers[alias]
   397→				if alias == cfg.CurrentServer {
   398→					fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
   399→				} else {
   400→					fmt.Printf("    %-16s %s\n", alias, srv.URL)
   401→				}
   402→			}
   403→
   404→			return nil
   405→		}
   406→
   407→		name := args[0]
   408→
   409→		// Check if name matches a server alias or URL
   410→		if _, ok := cfg.Servers[name]; ok {
   411→			cfg.CurrentServer = name
   412→			if err := config.Save(cfg); err != nil {
   413→				return err
   414→			}
   415→			fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
   416→			return nil
   417→		}
   418→
   419→		// Try matching by URL
   420→		for alias, srv := range cfg.Servers {
   421→			if srv.URL == strings.TrimRight(name, "/") {
   422→				cfg.CurrentServer = alias
   423→				if err := config.Save(cfg); err != nil {
