   425→				}
   426→				fmt.Printf("Switched to server %s (%s)\n", alias, srv.URL)
   427→				return nil
   428→			}
   429→		}
   430→
   431→		return fmt.Errorf("server %q not found — run: sandcastle use", name)
   432→	},
