   189→func (c *Client) PollDeviceToken(deviceCode string) (token string, pending bool, err error) {
   190→	status, body, err := c.doWithStatus("POST", "/api/auth/device_token", DeviceTokenRequest{DeviceCode: deviceCode})
   191→	if err != nil {
   192→		return "", false, err
   193→	}
   194→
   195→	switch status {
   196→	case 200:
   197→		var resp DeviceTokenResponse
   198→		if err := json.Unmarshal(body, &resp); err != nil {
   199→			return "", false, fmt.Errorf("parsing response: %w", err)
   200→		}
   201→		return resp.Token, false, nil
   202→	case 428: // Precondition Required — authorization_pending
   203→		return "", true, nil
   204→	default:
   205→		var apiErr APIError
   206→		if json.Unmarshal(body, &apiErr) == nil && apiErr.Error != "" {
   207→			return "", false, fmt.Errorf("%s", apiErr.Error)
   208→		}
   209→		return "", false, fmt.Errorf("unexpected status %d: %s", status, string(body))
   210→	}
   211→}
