   435→var setCmd = &cobra.Command{
   436→	Use:   "set <name> <temp|keep>",
   437→	Short: "Toggle sandbox between temporary and kept",
   438→	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
   439→
   440→  temp   Mark as temporary — will be removed when the CLI session exits
   441→  keep   Mark as kept — will not be auto-removed`,
   442→	Args: cobra.ExactArgs(2),
   443→	RunE: func(cmd *cobra.Command, args []string) error {
   444→		client, err := api.NewClient()
   445→		if err != nil {
   446→			return err
   447→		}
   448→		printServer(client)
   449→
   450→		sandbox, err := findSandboxByName(client, args[0])
   451→		if err != nil {
   452→			return err
   453→		}
   454→
   455→		mode := strings.ToLower(args[1])
   456→		var temp bool
   457→		switch mode {
   458→		case "temp":
   459→			temp = true
   460→		case "keep":
   461→			temp = false
   462→		default:
   463→			return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
   464→		}
   465→
   466→		sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
   467→		if err != nil {
   468→			return err
   469→		}
   470→
   471→		if temp {
   472→			fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
   473→		} else {
   474→			fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
   475→		}
   476→		return nil
   477→	},
   478→}
   479→
   480→func envTruthy(key string) bool {
   481→	v := strings.ToLower(os.Getenv(key))
   482→	return v == "1" || v == "true" || v == "yes"
   483→}
   484→
   485→func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
   486→	sandboxes, err := client.ListSandboxes()
   487→	if err != nil {
   488→		return nil, err
   489→	}
   490→	for _, s := range sandboxes {
   491→		if s.Name == name {
   492→			return &s, nil
   493→		}
   494→	}
   495→	return nil, fmt.Errorf("sandbox %q not found", name)
   496→}
