   241→		if len(sandboxes) == 0 {
   242→			fmt.Println("No sandboxes.")
   243→			return nil
   244→		}
   245→
   246→		hasRoute := false
   247→		for _, s := range sandboxes {
   248→			if len(s.Routes) > 0 {
   249→				hasRoute = true
   250→				break
   251→			}
   252→		}
   253→
   254→		w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
   255→		if hasRoute {
   256→			fmt.Fprintln(w, "NAME\tSTATUS\tPORT\tROUTE\tTAILSCALE IP\tIMAGE")
   257→		} else {
   258→			fmt.Fprintln(w, "NAME\tSTATUS\tPORT\tTAILSCALE IP\tIMAGE")
   259→		}
   260→		for _, s := range sandboxes {
   261→			name := s.Name
